local BaseIcon = LXImport(".BaseIcon")
-----------------------------------------------------------------
---@class SkillIcon:BaseIcon
local SkillIcon = LxClass("SkillIcon", BaseIcon)
-----------------------------------------------------------------

function SkillIcon:SkillIcon(wndClass)
	self._ownerWndClass = wndClass
end

function SkillIcon:OnCreate()
	self:RefreshUI()
end

function SkillIcon:SetTrans()
	local uiTrans 			= self._uiTrans
	self._uiSkillBg = CS.FindTrans(uiTrans,"SkillBg")
	if self._uiSkillBg then
		self._uiSkillLv = CS.FindTrans(self._uiSkillBg,"SkillLv")
	end
	self._uiUpSkillBg = CS.FindTrans(uiTrans,"UpSkillBg")
	if self._uiUpSkillBg then
		self._uiUpSkillLv = CS.FindTrans(self._uiUpSkillBg,"UpSkillLv")
	end
	self._uiUnLockBg = CS.FindTrans(uiTrans,"UnLockBg")
	self._uiUnLockLv = CS.FindTrans(uiTrans,"UnLockLv")



	self._isEnus = gLGameLanguage:IsEnglishVersion() or gLGameLanguage:IsVieVersion()
	if self._isEnus then
		self._uiUnLockBg = CS.FindTrans(uiTrans,"UnLockBg_En")
		self._uiUnLockLv = CS.FindTrans(uiTrans,"UnLockLv_En")
	end
	self._uiQuestion = CS.FindTrans(uiTrans,"Question ")
	self._uiLockImg = CS.FindTrans(uiTrans,"LockImg")
	self._uiAddImg = CS.FindTrans(uiTrans,"AddImg")
	self._uiEffIcon = CS.FindTrans(uiTrans,"EffIcon")
end

function SkillIcon:SetData()
	if self._itype ~= nil then
		self:RefreshHeroSkill()
	else
		self:RefreshSkillLv()
	end
	if self._wenhao ~= nil then
		CS.ShowObject(self._uiQuestion,self._wenhao)
	else
		CS.ShowObject(self._uiQuestion,false)
	end
	if self._lock ~= nil then
		CS.ShowObject(self._uiLockImg,self._lock)
		if self._lock then
			CS.ShowObject(self._uiSkillBg,not self._lock)
			CS.ShowObject(self._uiUpSkillBg,not self._lock)
		end
	end

	if self._showLvl ~= nil then
		CS.ShowObject(self._uiSkillBg, self._showLvl)
	end

	if self._add ~= nil then
		CS.ShowObject(self._uiAddImg,self._add)
	end
end

function SkillIcon:SetShowIcon(show,b)
	self._showIcon = show
	self._noSkillStatus = b
end

function SkillIcon:ShowWenHao(wenhao)
	self._wenhao = wenhao
end
