function SkillIcon:ShowAdd(b)
	self._add = b
end

function SkillIcon:ShowLock(isLock)
	self._lock = isLock
end

function SkillIcon:ShowLvl(isShow)
	self._showLvl = isShow
end

function SkillIcon:RefreshSkillLv()
	local skillLvNum = gModelHero:GetSkillLvBySkillId(self._key)
	CS.ShowObject(self._uiUpSkillBg,false)
	local showLv = false
	if skillLvNum then showLv = true end
	CS.ShowObject(self._uiSkillBg,showLv)
	if showLv then self:SetXUIText(self._uiSkillLv,skillLvNum)	end
end
------------------------- 天赋技能 -------------------------

------------------------- 英雄技能 -------------------------
-- 英雄技能
-- grade,isUp,needGrade,itype,isGuild:英雄阶级/公会技能等级，是否显示n+n形式的等级，开启需要的阶级/等级，等级显示类型，是否公会技能
function SkillIcon:SetSkillInfo(grade,isUp,needGrade,itype,isGuild)
	self._heroGrade = grade
	self._isUp = isUp
	self._needGrade = needGrade
	self._itype = itype
	self._isGuild = isGuild
end

function SkillIcon:RefreshHeroSkill()
	local isShow = true
	if not self._isUp then
		isShow = false
	end
	if self._showIcon ~= nil then
		CS.ShowObject(self._uiSkillBg,self._showIcon)
		CS.ShowObject(self._uiUpSkillBg,self._showIcon)
		CS.ShowObject(self._uiUnLockLv,self._showIcon)
		CS.ShowObject(self._uiUnLockBg,self._showIcon)
		return
	end
	local isGuild = self._isGuild
	local skillLvNum = gModelHero:GetSkillLvBySkillId(self._key)
	if self._itype == 1 then
		CS.ShowObject(self._uiSkillBg,true)
		CS.ShowObject(self._uiUpSkillBg,false)
		self:SetXUIText(self._uiSkillLv,skillLvNum)
	else
		CS.ShowObject(self._uiSkillBg,false)
		CS.ShowObject(self._uiUpSkillBg,true)
		local skillLvStr
		if not isShow then
			skillLvStr = skillLvNum
		else
			skillLvStr = ccClientText(10021)
			skillLvStr = string.replace(skillLvStr,skillLvNum,1)
		end
		self:SetXUIText(self._uiUpSkillLv,skillLvStr)
	end
	local UnLock = false
	local grade = self._heroGrade
	if grade then
		if grade < self._needGrade then
			local str = ccClientText(10036)
			if isGuild then str = ccClientText(10022) end
			str = string.replace(str,self._needGrade)
			UnLock = true
			self:SetXUIText(self._uiUnLockLv,str)
		end
	end
	CS.ShowObject(self._uiUnLockLv,UnLock)
	CS.ShowObject(self._uiUnLockBg,UnLock)
	self:SetIconAndIconBgGray(UnLock)
end
------------------------- 英雄技能 -------------------------

