function SkillIcon:SetIconAndIconBgGray(b)
	self:SetImageGray(self._uiIconBgTrans,b)
	self:SetImageGray(self._uiIconTrans,b)
end

function SkillIcon:RefreshUI()
	local icon,iconBg = gModelHero:GetSkillImgBySkillId(self._key)
	if self._noSkillStatus ~= nil then icon = "hero_icon_1" end
	if not string.isempty(icon) then
		CS.ShowObject(self._uiIconTrans,true)
		self:SetIcon(icon)
	else
		CS.ShowObject(self._uiIconTrans,false)
	end
	if not string.isempty(iconBg) then
		self:SetIconBg(iconBg)
	end
	local showEff = false
	local skillRef = gModelHero:GetSkillByStarId(self._key)
	if skillRef then
		local trumpSkill = skillRef.trumpSkill
		if trumpSkill ~= "" then
			showEff = true
			local rootTrans = nil
			if self._ownerWndClass then
				rootTrans = self._ownerWndClass:GetWndTrans()
			end
			self:SetImage(self._uiEffIcon, trumpSkill, nil,true)
		end
	end
	CS.ShowObject(self._uiEffIcon,showEff)
	if self._playAni then
		self:CreateAni()
	end
end

--[[
	data=
	{
		refId,
		trans,
		tipFunc,
		level,
	}
]]

function SkillIcon:Show(data)
	local tran = data.trans
	local refId = data.refId
	local func  = data.tipFunc
	local level = data.level
	self:Create(tran,refId,func)
	self:SetXUIText(self._uiSkillLv,level)
end

return SkillIcon
